import { useEffect, useState } from "react";
import { Search, BarChart3, Volume2, Eye, Activity } from "lucide-react";
import CompanyItem from "../components/CompanyItem";
import MetricCard from "../components/MetricCard";
import AIPrediction from "../components/AIPrediction";
import WelcomeMessage from "../components/WelcomeMessage";
import ChartArea from "../components/ChartArea";
import { fetchCompanies } from "../utils/api";

// ✅ Format helper
const formatNumber = (num, prefix = "") => {
  if (num === null || num === undefined || isNaN(num)) return "—";
  return prefix + new Intl.NumberFormat("en-IN").format(num);
};

const formatPercent = (num) => {
  if (num === null || num === undefined || isNaN(num)) return "0.00%";
  const sign = num >= 0 ? "+" : "";
  return `${sign}${num.toFixed(2)}%`;
};

const StockDashboard = () => {
  const [companies, setCompanies] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  // ✅ Fetch company list
  useEffect(() => {
    const loadCompanies = async () => {
      setIsLoading(true);
      try {
        const res = await fetchCompanies();
        setCompanies(Array.isArray(res) ? res : []); // safe check
      } catch (err) {
        console.error("Error fetching companies:", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadCompanies();
  }, []);

  // ✅ Safe search filter
  const filteredCompanies =
    companies.length > 0
      ? companies.filter(
          (c) =>
            c?.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c?.symbol?.toLowerCase().includes(searchTerm.toLowerCase())
        )
      : [];

  // ✅ Handle company selection
  const handleCompanySelect = (company) => {
    setSelectedCompany(company);
    setIsLoading(true);
    setTimeout(() => setIsLoading(false), 800); // mock loading for chart
  };

  // ✅ Chart data with safe checks
  const chartData =
    selectedCompany && Array.isArray(selectedCompany.historical_data)
      ? {
          labels: selectedCompany.historical_data.map((d) => d.date || ""),
          datasets: [
            {
              data: selectedCompany.historical_data.map(
                (d) => d.close ?? d.price ?? 0
              ),
              borderColor: "#3b82f6",
              backgroundColor: "rgba(59, 130, 246, 0.08)",
              borderWidth: 3,
              fill: true,
              tension: 0.3,
            },
          ],
        }
      : { labels: [], datasets: [] };

  return (
    <div className="flex h-screen bg-gradient-to-br from-slate-50 to-blue-50">
      {/* Sidebar */}
      <div className="w-96 bg-white shadow-2xl border-r border-gray-200 flex flex-col">
        {/* Search */}
        <div className="p-4 bg-gradient-to-r from-gray-50 to-blue-50 border-b border-gray-100">
          <div className="relative group">
            <Search
              className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"
              size={18}
            />
            <input
              type="text"
              placeholder="Search stocks..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 bg-white border border-gray-200 rounded-2xl focus:ring-2 focus:ring-blue-400 outline-none"
            />
          </div>
        </div>

        {/* Company List */}
        <div className="flex-1 overflow-y-auto py-2">
          {filteredCompanies.length > 0 ? (
            filteredCompanies.map((c) => (
              <CompanyItem
                key={c.id}
                company={c}
                isActive={selectedCompany?.id === c.id}
                onClick={() => handleCompanySelect(c)}
              />
            ))
          ) : (
            <p className="text-gray-500 text-center mt-6">No companies found</p>
          )}
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Company Info + Metrics */}
        {selectedCompany && (
          <div className="p-6 bg-white shadow-sm border-b border-gray-200">
            <div className="flex flex-col xl:flex-row xl:items-center xl:justify-between gap-6">
              {/* Company Info */}
              <div className="flex items-center gap-4">
                <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-2xl flex items-center justify-center text-white font-bold text-xl shadow-lg">
                  {selectedCompany.symbol?.substring(0, 2)}
                </div>
                <div>
                  <h1 className="text-2xl font-bold text-gray-900 mb-1">
                    {selectedCompany.name}
                  </h1>
                  <div className="flex items-center gap-3 text-sm text-gray-600">
                    <span className="px-3 py-1 bg-blue-50 text-blue-700 rounded-full font-medium">
                      {selectedCompany.symbol}
                    </span>
                    <span>NSE</span>
                    <span>•</span>
                    <span>{selectedCompany.sector || "—"}</span>
                  </div>
                </div>
              </div>

              {/* Metrics */}
              <div className="grid grid-cols-2 xl:grid-cols-4 gap-4">
                <MetricCard
                  label="Current Price"
                  value={formatNumber(selectedCompany?.current_price, "₹")}
                  icon={Eye}
                  subValue={`${selectedCompany?.change >= 0 ? "+" : ""}${
                    selectedCompany?.change?.toFixed?.(2) || "0.00"
                  } (${formatPercent(selectedCompany?.changePercent)})`}
                />
                <MetricCard
                  label="Market Cap"
                  value={formatNumber(selectedCompany?.market_cap, "₹")}
                  icon={BarChart3}
                  subValue="Total value"
                />
                <MetricCard
                  label="Volume"
                  value={formatNumber(selectedCompany?.volume)}
                  icon={Volume2}
                  subValue="Today's trading"
                />
                <MetricCard
                  label="P/E Ratio"
                  value={selectedCompany?.pe ?? "—"}
                  icon={Activity}
                  subValue="Price to earnings"
                />
              </div>
            </div>
          </div>
        )}

        {/* Chart + AI Prediction */}
        <div className="flex-1 p-6 grid grid-cols-3 gap-6">
          {/* Chart Area */}
          <div className="col-span-2">
            <ChartArea
              selectedCompany={selectedCompany}
              isLoading={isLoading}
              chartData={chartData}
            />
          </div>

          {/* AI Predictions */}
          {selectedCompany ? (
            <div className="col-span-1 bg-white rounded-3xl shadow-xl border border-gray-200 p-4">
              <AIPrediction company={selectedCompany} isLoading={isLoading} />
            </div>
          ) : (
            <WelcomeMessage />
          )}
        </div>
      </div>
    </div>
  );
};

export default StockDashboard;
